## 1. Header: `include/pdb_native.h`

```cpp
#pragma once
#include <cstdint>
#include <windows.h>

namespace RawrXD {
namespace PDB {

// MSF v7.00 SuperBlock (packed)
#pragma pack(push, 1)
struct MSFSuperBlock {
    char     magic[32];          // "Microsoft C/C++ MSF 7.00\r\n\032DS\0\0"
    uint32_t blockSize;          // 512, 1024, 2048, or 4096
    uint32_t freeBlockMapBlock;  // Index of free block map
    uint32_t numBlocks;          // Total blocks in file
    uint32_t numDirectoryBytes;  // Size of stream directory
    uint32_t reserved;
    uint32_t blockMapAddr;       // Block index of block map (list of pages containing directory)
};

// PDB Info Stream (Stream 1)
struct PDBInfoHeader {
    uint32_t version;            // PDB version signature
    uint32_t timeDateStamp;
    uint32_t age;                // Incremented on rebuild
    uint8_t  guid[16];           // Unique identifier for this PDB
};

// DBI Stream Header (Stream 3)
struct DBIHeader {
    int32_t  versionSignature;   // -1 (0xFFFFFFFF) for VC7+
    uint32_t versionHeader;
    uint32_t age;
    uint16_t globalStreamIndex;  // Stream index of global symbol hash
    uint16_t publicStreamIndex;  // Stream index of public symbol hash
    uint16_t symRecordStream;    // Stream index of actual symbol records
    uint16_t reserved1;
    uint16_t modInfoSize;
    uint16_t sectionContribSize;
    uint16_t sectionMapSize;
    uint16_t sourceInfoSize;
    uint16_t typeServerMapSize;
    uint32_t mfcTypeServerIndex;
    uint16_t reserved2;
    uint16_t optionalDbgHeaderSize;
    uint16_t reserved3;
    uint32_t machine;            // IMAGE_FILE_MACHINE_X64, etc.
};

// CV Symbol Records (CodeView)
struct CVRecordHeader {
    uint16_t recLen;             // Record length (not including this header)
    uint16_t recTyp;             // Record type (S_PUB32, etc.)
};

struct CVPubSym32 {
    uint16_t recLen;
    uint16_t recTyp;             // S_PUB32 = 0x110E
    uint32_t pubSymFlags;
    uint32_t off;                // Section offset
    uint16_t seg;                // Section index (1-based)
    // char name[];              // Null-terminated name follows
};

struct CVProcSym32 {
    uint16_t recLen;
    uint16_t recTyp;             // S_GPROC32 = 0x1110, S_LPROC32 = 0x1114
    uint32_t parent;
    uint32_t end;
    uint32_t next;
    uint32_t len;                // Procedure length
    uint32_t dbgStart;
    uint32_t dbgEnd;
    uint32_t typ;                // Type index
    uint32_t off;                // Section offset
    uint16_t seg;                // Section index
    uint8_t  flags;
    // char name[];              // Null-terminated name follows
};

// PE RSDS Debug Info
struct RSDS_DEBUG_INFO {
    uint32_t signature;          // "RSDS" (0x53445352)
    uint8_t  guid[16];
    uint32_t age;
    // char pdbName[];           // Null-terminated PDB path follows
};
#pragma pack(pop)

// Symbol types we care about
const uint16_t S_PUB32       = 0x110E;
const uint16_t S_GPROC32     = 0x1110;
const uint16_t S_LPROC32     = 0x1114;
const uint16_t S_GPROC32_ID  = 0x1147;
const uint16_t S_LPROC32_ID  = 0x1148;

// DBI Optional Debug Header indices
const int DBI_DBG_SECTION_HDR = 5;  // Section header stream index

// Result structure (no exceptions)
struct PDBResult {
    bool     success;
    char     detail[256];
    uint32_t code;               // Error code for programmatic handling
    
    static PDBResult ok(const char* msg = "OK") {
        PDBResult r; r.success = true; r.code = 0;
        strncpy_s(r.detail, msg, sizeof(r.detail)-1);
        return r;
    }
    static PDBResult error(const char* msg, uint32_t errCode) {
        PDBResult r; r.success = false; r.code = errCode;
        strncpy_s(r.detail, msg, sizeof(r.detail)-1);
        return r;
    }
};

// Error codes
const uint32_t PDB_ERR_FILE_OPEN      = 1;
const uint32_t PDB_ERR_FILE_MAP       = 2;
const uint32_t PDB_ERR_INVALID_MAGIC  = 3;
const uint32_t PDB_ERR_INVALID_FORMAT = 4;
const uint32_t PDB_ERR_STREAM_OOB     = 5;
const uint32_t PDB_ERR_ALLOC_FAIL     = 6;
const uint32_t PDB_ERR_NOT_LOADED     = 7;
const uint32_t PDB_ERR_SYMBOL_NOT_FOUND = 8;
const uint32_t PDB_ERR_CACHE_WRITE    = 9;
const uint32_t PDB_ERR_DOWNLOAD_FAIL  = 10;
const uint32_t PDB_ERR_PE_NO_DEBUG_DIR = 11;

// Stream indices
const uint32_t STREAM_PDB = 1;
const uint32_t STREAM_TPI = 2;
const uint32_t STREAM_DBI = 3;
const uint32_t STREAM_IPI = 4;

// Section header (extracted from PE/PDB)
struct PDBSectionHeader {
    uint32_t virtualSize;
    uint32_t virtualAddress;
    uint32_t sizeOfRawData;
    uint32_t pointerToRawData;
    uint32_t pointerToRelocations;
    uint32_t pointerToLinenumbers;
    uint16_t numberOfRelocations;
    uint16_t numberOfLinenumbers;
    uint32_t characteristics;
};

// Resolved symbol info
enum class CVSymbolType : uint16_t {
    Unknown = 0,
    Public = S_PUB32,
    GlobalProc = S_GPROC32,
    LocalProc = S_LPROC32
};

struct ResolvedSymbol {
    const char*    name;
    uint32_t       nameLen;
    uint64_t       rva;              // Resolved virtual address
    uint16_t       section;          // 1-based section index
    uint32_t       sectionOffset;
    uint32_t       size;             // For procedures
    CVSymbolType   type;
    bool           isFunction;
    bool           isPublic;
};

// Symbol visitor callback
typedef bool (*SymbolVisitor)(const ResolvedSymbol* sym, void* userData);

// Native PDB Parser (single file instance)
class NativePDBParser {
public:
    NativePDBParser();
    ~NativePDBParser();
    
    // Lifecycle
    PDBResult load(const wchar_t* pdbPath);
    void      unload();
    
    // Identity
    PDBResult getGuid(uint8_t guidOut[16]) const;
    uint32_t  getAge() const;
    bool      isLoaded() const { return m_pBase != nullptr; }
    
    // Queries
    PDBResult findPublicSymbol(const char* name, uint64_t* rvaOut) const;
    PDBResult findSymbolByRVA(uint64_t rva, ResolvedSymbol* symOut) const;
    PDBResult enumeratePublicSymbols(SymbolVisitor visitor, void* userData) const;
    PDBResult enumerateProcedures(SymbolVisitor visitor, void* userData) const;
    
    // Section info
    const PDBSectionHeader* getSectionHeader(uint32_t index) const;
    uint32_t                getSectionCount() const { return m_numSections; }
    uint64_t                sectionOffsetToRVA(uint16_t section, uint32_t offset) const;
    bool                    rvaToSectionOffset(uint64_t rva, uint16_t* section, uint32_t* offset) const;
    
    // Raw stream access
    uint32_t  getStreamSize(uint32_t streamIndex) const;
    PDBResult readStream(uint32_t streamIndex, uint32_t offset, void* buffer, uint32_t size) const;
    const uint8_t* getStreamByte(uint32_t streamIndex, uint32_t offset) const;

private:
    // File handles
    HANDLE   m_hFile = INVALID_HANDLE_VALUE;
    HANDLE   m_hMapping = nullptr;
    const uint8_t* m_pBase = nullptr;
    uint64_t m_fileSize = 0;
    
    // MSF structures
    const MSFSuperBlock* m_superBlock = nullptr;
    uint32_t m_blockSize = 0;
    uint32_t m_numStreams = 0;
    uint32_t* m_streamSizes = nullptr;      // Array[numStreams]
    uint32_t** m_streamPages = nullptr;     // Array[numStreams][numPages]
    
    // PDB identity
    uint8_t  m_guid[16] = {};
    uint32_t m_age = 0;
    uint32_t m_pdbVersion = 0;
    
    // DBI-derived indices
    uint16_t m_globalSymStream = 0xFFFF;
    uint16_t m_publicSymStream = 0xFFFF;
    uint16_t m_symRecordStream = 0xFFFF;
    uint16_t m_sectionHdrStream = 0xFFFF;
    uint32_t m_machine = 0;
    
    // Section headers (from DBI optional header)
    PDBSectionHeader* m_sectionHeaders = nullptr;
    uint32_t m_numSections = 0;
    
    // Internal
    PDBResult parseStreamDirectory();
    PDBResult parsePDBInfoStream();
    PDBResult parseDBIStream();
    PDBResult parseSectionHeaders();
    PDBResult parsePublicSymbolStream();
    bool      readStreamRange(uint32_t streamIndex, uint32_t offset, uint8_t* dest, uint32_t size) const;
};

// Symbol Server Configuration
struct SymbolServerConfig {
    const wchar_t* serverUrl;        // e.g., L"https://msdl.microsoft.com/download/symbols"
    const wchar_t* cachePath;        // e.g., L"C:\Symbols" (nullptr for default)
    uint32_t       timeoutMs;
    uint32_t       maxRetries;
    bool           enableCompression;
    bool           enabled;
};

// Download progress callback
typedef void (*PDBDownloadProgressCallback)(const char* pdbName, uint64_t bytesReceived, uint64_t bytesTotal, void* userData);

// Symbol Server Client
class PDBSymbolServer {
public:
    PDBSymbolServer();
    ~PDBSymbolServer();
    
    PDBResult configure(const SymbolServerConfig& config);
    
    // Cache operations
    PDBResult findInCache(const char* pdbName, const uint8_t guid[16], uint32_t age,
                          wchar_t* pathOut, uint32_t pathMaxChars) const;
    PDBResult download(const char* pdbName, const uint8_t guid[16], uint32_t age,
                       wchar_t* pathOut, uint32_t pathMaxChars);
    PDBResult clearCache();
    uint64_t  getCacheSizeBytes() const;
    
    void      setProgressCallback(PDBDownloadProgressCallback fn, void* userData);

private:
    SymbolServerConfig m_config;
