    void* m_progressData = nullptr;
    
    void buildGuidAgeString(const uint8_t guid[16], uint32_t age, char* out, uint32_t maxLen) const;
    void buildCachePath(const char* pdbName, const char* guidAge, wchar_t* out, uint32_t maxChars) const;
    void buildDownloadUrl(const char* pdbName, const char* guidAge, wchar_t* out, uint32_t maxChars) const;
    PDBResult ensureCacheDirectory(const wchar_t* dirPath) const;
    PDBResult downloadFile(const wchar_t* url, const wchar_t* destPath);
