// Manager (singleton coordinator)
class PDBManager {
public:
    static PDBManager& instance();
    
    PDBResult configure(const SymbolServerConfig& config);
    
    // Module loading (extract RSDS from PE, download PDB, load parser)
    PDBResult loadForModule(const char* moduleName, const uint8_t* peBase, uint64_t peSize);
    PDBResult loadPDB(const char* moduleName, const wchar_t* pdbPath);
