    // Symbol resolution
    PDBResult resolveSymbol(const char* name, uint64_t* rvaOut, const char** moduleOut) const;
    PDBResult resolveRVA(const char* moduleName, uint64_t rva, ResolvedSymbol* symOut) const;
    
    // Enumeration
    const NativePDBParser* getParser(const char* moduleName) const;
    uint32_t               getLoadedModuleCount() const;
    const char*            getLoadedModuleName(uint32_t index) const;
    
    // Stats
    struct Stats {
        uint32_t modulesLoaded;
        uint32_t cacheHits;
        uint32_t downloadCount;
        uint32_t lookupCount;
    };
